use-focus-zone-basic.raw:
"use client";

import { KeyboardProvider, useFocusZone, useScopedNavigation } from "@diffgazer/keys";
import { useId, useRef } from "react";

type Zone = "sidebar" | "main";

function Layout() {
  const { zone, isZone } = useFocusZone<Zone>({
    initial: "sidebar",
    zones: ["sidebar", "main"],
    transitions: ({ zone, key }) => {
      if (zone === "sidebar" && key === "ArrowRight") return "main";
      if (zone === "main" && key === "ArrowLeft") return "sidebar";
      return null;
    },
  });

  return (
    <div>
      <p>
        <span style={{ fontWeight: zone === "sidebar" ? 700 : 400 }}>Sidebar</span>
        {" / "}
        <span style={{ fontWeight: zone === "main" ? 700 : 400 }}>Main</span>
        {" -- ArrowLeft / ArrowRight switch zones"}
      </p>
      <div style={{ display: "flex", gap: 16 }}>
        <Pane
          title="Sidebar"
          items={["Dashboard", "Settings", "Profile"]}
          active={isZone("sidebar")}
          enabled={zone === "sidebar"}
        />
        <Pane
          title="Main"
          items={["Item A", "Item B", "Item C", "Item D"]}
          active={isZone("main")}
          enabled={zone === "main"}
        />
      </div>
    </div>
  );
}

function Pane({
  title,
  items,
  active,
  enabled,
}: {
  title: string;
  items: string[];
  active: boolean;
  enabled: boolean;
}) {
  const containerRef = useRef<HTMLDivElement>(null);
  const headingId = useId();

  const { isHighlighted } = useScopedNavigation({
    containerRef,
    role: "option",
    wrap: true,
    enabled,
  });

  return (
    <div
      style={{
        minWidth: 160,
        padding: 8,
        borderWidth: 1,
        borderStyle: "solid",
        borderColor: active ? "currentColor" : "transparent",
      }}
    >
      <h4 id={headingId}>{title}</h4>
      <div ref={containerRef} role="listbox" aria-labelledby={headingId}>
        {items.map((item) => (
          // biome-ignore lint/a11y/useFocusableInteractive: WAI-ARIA listbox pattern — options stay non-focusable; the listbox container holds focus and active state is tracked via aria-selected.
          <div
            key={item}
            role="option"
            data-value={item}
            aria-selected={isHighlighted(item)}
            style={{ padding: "4px 8px", fontWeight: isHighlighted(item) ? 700 : 400 }}
          >
            {item}
          </div>
        ))}
      </div>
    </div>
  );
}

export default function UseFocusZoneBasic() {
  return (
    <KeyboardProvider>
      <Layout />
    </KeyboardProvider>
  );
}

use-focus-zone-tab-cycle.raw:
"use client";

import { KeyboardProvider, useFocusZone } from "@diffgazer/keys";
import { useRef } from "react";

type Zone = "search" | "results" | "preview";
const zones = ["search", "results", "preview"] as const;

function FinderLayout() {
  const searchRef = useRef<HTMLInputElement>(null);
  const resultsRef = useRef<HTMLDivElement>(null);
  const previewRef = useRef<HTMLDivElement>(null);

  const { zone, getZoneProps } = useFocusZone<Zone>({
    initial: "search",
    zones,
    // Tab / Shift+Tab cycle through the three regions in order.
    tabCycle: zones,
    allowInInput: true,
    focus: {
      targets: {
        search: searchRef,
        results: resultsRef,
        preview: previewRef,
      },
    },
  });

  const paneStyle = (z: Zone) => ({
    flex: 1,
    minWidth: 120,
    padding: 8,
    border: "1px solid currentColor",
    outline: zone === z ? "2px solid currentColor" : "none",
  });

  return (
    <div>
      <p>Tab and Shift+Tab cycle Search → Results → Preview. Active zone: {zone}.</p>
      <div style={{ display: "flex", gap: 12 }}>
        <div {...getZoneProps("search")} style={paneStyle("search")}>
          <input
            ref={searchRef}
            aria-label="Search"
            placeholder="Search"
            style={{ width: "100%" }}
          />
        </div>
        <div
          ref={resultsRef}
          tabIndex={-1}
          {...getZoneProps("results")}
          style={paneStyle("results")}
        >
          Results
        </div>
        <div
          ref={previewRef}
          tabIndex={-1}
          {...getZoneProps("preview")}
          style={paneStyle("preview")}
        >
          Preview
        </div>
      </div>
    </div>
  );
}

export default function UseFocusZoneTabCycle() {
  return (
    <KeyboardProvider>
      <FinderLayout />
    </KeyboardProvider>
  );
}
